mapper.insert:
INSERT INTO NMCP_FRND_INVI_USIM (
    SYS_RMON
    ,PHONE
    ,NAME
    ,COMMEND_ID
    ,AGREE
    ,FRND_NAME
    ,FRND_PHONE
    ,FRND_POST
    ,FRND_ADDR
    ,FRND_ADDR_DTL
    ,SYS_RDATE
) VALUES (
    TO_CHAR(SYSDATE,'YYYYMM')
    ,#{phone}
    ,#{name}
    ,#{commendId}
    ,#{agree}
    ,#{frndName}
    ,#{frndPhone}
    ,#{frndPost}
    ,#{frndAddr}
    ,#{frndAddrDtl}
    ,SYSDATE
)
